// VectorIQ — Tech Spec HTML Builder (shared, plain JS — no React/Babel, no Firebase)
// Pure function: asset data in, standalone tech-spec HTML document out.
// Loaded as a plain <script> (like /calculations/llpCalculator.js) so the
// SAME function is available to:
//   - index.html (authenticated app — "Generate Tech Spec" button)
//   - share.html (public, unauthenticated share-link page)
// without duplicating ~150 lines of HTML-building logic in two places.
// Depends on calcLLPRem / lowestLimiter (calculations/llpCalculator.js),
// which must be loaded BEFORE this script — same pattern already used by
// index.html. fmtDate/fmtHHMM moved here from index.html for the same reason
// (single source of truth, used by both pages).
function fmtDate(s){try{if(!s)return"—";let d=s;if(/^\d{2}\/\d{2}\/\d{4}$/.test(s)){const m=s.split("/");d=m[2]+"-"+m[1]+"-"+m[0];}return new Date(d).toLocaleDateString("en-GB",{day:"2-digit",month:"short",year:"numeric"});}catch{return s||"—";}}
function fmtHHMM(dec){if(!dec&&dec!==0)return"—";if(typeof dec==="string"&&dec.includes(":"))return dec;return`${Math.floor(dec)}:${String(Math.round((dec%1)*60)).padStart(2,"0")}`;}

const VECTORIQ_BANNER="data:image/png;base64,";
const TECH_SPEC_LOGO="data:image/png;base64,";
// To update this logo in future: replace the base64 string above with a new one.
// Convert any PNG/JPG via: python3 -c "import base64; print(base64.b64encode(open('logo.png','rb').read()).decode())"



function buildTechSpecHTML(asset,engPhoto="",logoOverride=null){
  const logoUrl=logoOverride?.url||TECH_SPEC_LOGO;
  const logoWidth=logoOverride?.width||200;
  const today=new Date().toLocaleDateString("en-GB",{day:"2-digit",month:"long",year:"numeric"});
  const af=asset.airframe||{};const lg=asset.landingGear||{};const apu=asset.apu||{};
  const engineOnly=asset._engineOnly;
  const enginePos=asset._enginePos||1;
  const specCSS=`@page{size:A4;margin:14mm 18mm}body{font-family:Arial,sans-serif;color:#111;font-size:11px;line-height:1.45;margin:0;print-color-adjust:exact;-webkit-print-color-adjust:exact;color-adjust:exact}
.cover{text-align:center;page-break-after:always;padding:46px 30px}.cover h1{color:#323F42;font-size:24px;margin:0 0 5px}.cover h2{color:#323F42;font-size:17px;margin:0 0 18px}
.viq-banner{background:#ffffff;border-bottom:2px solid #C9A84C;margin:-46px -30px 24px -30px;padding:8px 0;text-align:center}
.viq-banner img{height:28px;width:auto;display:inline-block}
.cover .meta{color:#374151;font-size:13px;line-height:2.2}.cover .disc{font-size:9px;color:#6b7280;max-width:460px;margin:24px auto 0;line-height:1.6;text-align:left}
.cover .dt{margin-top:14px;font-size:12px;color:#374151}
h3{background:#323F42;color:#FFFFFF;font-size:11.5px;padding:5px 10px;border-radius:4px;margin:18px 0 7px;letter-spacing:0.04em}
table{width:100%;border-collapse:collapse;margin-bottom:9px;font-size:10.5px}
th{background:#f1f5f9;color:#374151;font-weight:700;text-align:left;padding:5px 8px;font-size:9.5px;text-transform:uppercase;letter-spacing:0.04em;border:1px solid #e2e8f0}
td{padding:5px 8px;border:1px solid #e2e8f0;vertical-align:top}
.kv td:first-child{color:#6b7280;font-weight:600;width:180px}
.pb{page-break-before:always;height:0;margin:0;padding:0}
.pgfooter{text-align:center;font-size:8px;color:#9ca3af;letter-spacing:0.05em;text-transform:uppercase;margin-top:24px;border-top:1px solid #e2e8f0;padding-top:7px}
.footer{text-align:center;font-size:8px;color:#aaa;margin-top:20px;border-top:1px solid #e2e8f0;padding-top:7px}`;
  const PAGE_FOOTER='<div class="pgfooter">Powered by TailiQ Fleet Intelligence Platform</div>';
  const llpRows=(llps,csn)=>!llps?.length?'<tr><td colspan="4" style="color:#aaa;font-style:italic">No LLP data entered</td></tr>':llps.map(l=>{const r=calcLLPRem(l,csn);return`<tr><td>${l.desc||""}</td><td style="font-family:monospace">${l.pn||""}</td><td style="font-family:monospace">${l.sn||""}</td><td style="font-weight:700;color:${r<1000?"#dc2626":r<3000?"#d97706":"#111"}">${r.toLocaleString()}</td></tr>`;}).join("");
  const svRows=(visits,currentFH,currentFC)=>{if(!visits||!visits.length)return'<tr><td colspan="4" style="color:#aaa;font-style:italic">No shop visits recorded</td></tr>';const mroLine=(mro)=>mro?'<br/><span style="font-size:9px;color:#6b7280">'+mro+'</span>':"";const rows=visits.map(sv=>'<tr><td>'+(sv.details||"")+'</td><td>'+fmtDate(sv.date)+mroLine(sv.mro)+'</td><td style="font-family:monospace">'+(fmtHHMM(sv.fh)||"")+'</td><td style="font-family:monospace">'+(sv.fc?sv.fc.toLocaleString():"")+'</td></tr>').join("");const last=visits[visits.length-1];const sinceFH=currentFH&&last.fh?currentFH-last.fh:null;const sinceFC=currentFC&&last.fc?currentFC-last.fc:null;const sinceDays=last.date?Math.floor((new Date()-new Date(last.date))/86400000):null;const sinceRow='<tr style="background:#f1f5f9"><td colspan="2" style="color:#323F42;font-weight:700">Since Last Shop Visit</td><td style="font-family:monospace">'+(sinceFH!==null?fmtHHMM(sinceFH):"—")+'</td><td style="font-family:monospace">'+(sinceFC!==null?sinceFC.toLocaleString():"—")+'</td></tr><tr style="background:#f1f5f9"><td colspan="4" style="color:#6b7280;font-size:9px">Days since last shop visit: '+(sinceDays!==null?sinceDays.toLocaleString():"—")+'</td></tr>';return rows+sinceRow;};
  const engSec=(eng,pos)=>{if(!eng)return"";const ll=lowestLimiter(eng);return`<h3>Engine #${pos} — ESN ${eng.sn||"—"}</h3>
<table class="kv"><tr><td>Engine Type</td><td>${eng.type||"—"}</td><td style="color:#6b7280;font-weight:600;width:120px">Thrust</td><td>${eng.thrust||"—"}</td></tr>
<tr><td>TSN</td><td>${fmtHHMM(eng.currentFH)}</td><td style="color:#6b7280;font-weight:600">CSN</td><td>${(eng.currentFC||0).toLocaleString()}</td></tr>
<tr><td>Lowest LLP Limiter</td><td colspan="3" style="font-weight:700;color:${ll!==null&&ll<1000?"#dc2626":ll!==null&&ll<3000?"#d97706":"#111"}">${ll!==null?ll.toLocaleString()+" FC":"No LLP data"}</td></tr></table>
<p style="font-weight:700;font-size:10px;margin:8px 0 4px">Life Limited Parts</p>
<table><thead><tr><th>LLP Descriptor</th><th>P/N</th><th>S/N</th><th>FC Remaining</th></tr></thead><tbody>${llpRows(eng.llps,eng.currentFC)}</tbody></table>
<p style="font-weight:700;font-size:10px;margin:8px 0 4px">Shop Visit History</p>
<table><thead><tr><th>Details</th><th>Date / MRO</th><th>TSN</th><th>CSN</th></tr></thead><tbody>${svRows(eng.shopVisits,eng.currentFH,eng.currentFC)}</tbody></table>`;};
  const lgFromDDMMYYYY=(s)=>{if(!s)return"";const m=/^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s);if(m)return m[3]+"-"+m[2]+"-"+m[1];return s;};
  const lgFmtDate=(s)=>fmtDate(s);
  const lgSec=(g,title)=>{
    if(!g)return"";
    const intervalCycles=g.overhaulIntervalCycles!=null?g.overhaulIntervalCycles:20000;
    const hasRefPair=g.refLegFC!=null&&g.refAirframeFC!=null;
    let curFH=null,curFC=null,curSource="";
    if(g.currentFC!=null){curFH=g.currentFH;curFC=g.currentFC;curSource="Ground Truth";}
    else if(hasRefPair){curFH=(g.refLegFH||0)+((af.currentFH||0)-(g.refAirframeFH||0));curFC=g.refLegFC+((af.currentFC||0)-g.refAirframeFC);curSource="Calculated";}
    const totalsCell=curFC!=null?('FH: '+fmtHHMM(curFH)+'&nbsp; CSN: '+Math.round(curFC).toLocaleString()+' ('+curSource+')'):"—";
    const cyclesRemaining=(g.lastOverhaulFC!=null&&curFC!=null)?(g.lastOverhaulFC+intervalCycles)-curFC:null;
    const nextDueCell=lgFmtDate(g.nextDue)+(cyclesRemaining!=null?' / '+Math.round(cyclesRemaining).toLocaleString()+' cyc rem':"");
    // "Since Last Overhaul" diffs the leg's current total against its own
    // CSN/TSN at the last overhaul — same leg-CSN scale on both sides, so no
    // airframe figure is needed (the Reference Reading and Last Overhaul
    // Record are independent inputs and may not share a date).
    const sinceFH=(curFH!=null&&g.lastOverhaulFH!=null)?curFH-g.lastOverhaulFH:null;
    const sinceFC=(curFC!=null&&g.lastOverhaulFC!=null)?curFC-g.lastOverhaulFC:null;
    const lastDateISO=lgFromDDMMYYYY(g.lastOverhaulDate);
    const sinceDays=lastDateISO?Math.floor((new Date()-new Date(lastDateISO))/86400000):null;
    return'<table style="margin-bottom:14px"><thead><tr><th colspan="5" style="background:#323F42;color:#FFFFFF;font-size:11px">'+title+'</th></tr><tr><th>Part Number</th><th>Serial Number</th><th>Manufacturer</th><th>Totals Since New</th><th>Next Overhaul Due (Cal / Cyc)</th></tr></thead><tbody><tr><td>'+( g.pn||"—")+'</td><td>'+(g.sn||"—")+'</td><td>'+(g.mfr||"—")+'</td><td>'+totalsCell+'</td><td style="font-weight:700">'+ nextDueCell+'</td></tr></tbody></table>'+'<table style="margin-bottom:14px"><thead><tr><th>Last Overhaul Date</th><th>Leg FH at OH</th><th>Leg CSN at OH</th><th>Days Since</th><th>FH Since</th><th>CSN Since</th></tr></thead><tbody><tr><td>'+lgFmtDate(g.lastOverhaulDate)+'</td><td>'+(g.lastOverhaulFH!=null?fmtHHMM(g.lastOverhaulFH):"—")+'</td><td>'+(g.lastOverhaulFC!=null?g.lastOverhaulFC.toLocaleString():"—")+'</td><td>'+(sinceDays!==null?sinceDays.toLocaleString():"—")+'</td><td>'+(sinceFH!=null?fmtHHMM(sinceFH):"—")+'</td><td>'+(sinceFC!=null?Math.round(sinceFC).toLocaleString():"—")+'</td></tr></tbody></table>';
  };
  if(engineOnly){
    const eng=asset.engines?.[0];
    const ll=lowestLimiter(eng);
    return`<!DOCTYPE html><html><head><meta charset="utf-8"><title>Engine Spec ESN ${eng?.sn}</title><style>${specCSS}</style></head><body>
<div class="cover">
  <div class="viq-banner"><img src="${VECTORIQ_BANNER}" alt="VectorIQ"/></div>
  <img src="${logoUrl}" alt="Maverick Horizon" style="width:${logoWidth}px;border-radius:0;margin-bottom:24px"/><br>
  <h1>Engine Technical Specification</h1>
  <h2>Engine Serial Number: ${eng?.sn||"—"}</h2>
  <div class="meta">Aircraft MSN: <b>${asset.msn}</b><br>Registration: <b>${asset.registration||"—"}</b><br>Engine Type: <b>${eng?.type||"—"}</b><br>Position: <b>Engine #${enginePos}</b><br>Operator: <b>${asset.operator||"—"}</b></div>
  ${engPhoto?`<img src="${engPhoto}" style="width:420px;max-height:220px;object-fit:cover;border-radius:6px;margin:18px auto 0;display:block;box-shadow:0 4px 16px rgba(0,0,0,0.2)"/>`:""}
  <div class="dt">Date: ${today}</div>
</div>
${engSec(eng,enginePos)}
${PAGE_FOOTER}
</body></html>`;
  }
  return`<!DOCTYPE html><html><head><meta charset="utf-8"><title>Tech Spec MSN ${asset.msn}</title><style>${specCSS}</style></head><body>
<div class="cover">
  <div class="viq-banner"><img src="${VECTORIQ_BANNER}" alt="VectorIQ"/></div>
  <img src="${logoUrl}" alt="Maverick Horizon" style="width:${logoWidth}px;border-radius:0;margin-bottom:24px"/><br>
  <h1>Asset Technical Specification</h1>
  <h2>Manufacturer Serial Number: ${asset.msn}</h2>
  <div class="meta">Manufacturer: <b>${asset.manufacturer||"—"}</b><br>Model: <b>${asset.model||"—"}</b><br>Registration: <b>${asset.registration||"—"}</b><br>Operator: <b>${asset.operator||"—"}</b></div>
  ${(()=>{const coverPhoto=(asset.photos||[]).find(p=>p.label==="Airframe");return coverPhoto?.url?`<img src="${coverPhoto.url}" style="width:420px;max-height:200px;object-fit:cover;border-radius:6px;margin:18px auto 0;display:block;box-shadow:0 4px 16px rgba(0,0,0,0.2)"/>`:"";})()}
  <div class="disc">${asset.disclaimer||"This outline specification has been prepared based on the information available to Vector Group at the relevant time. The recipient must verify the information provided independently."}</div>
  <div class="dt">Date: ${today}</div>
</div>
<h3>Asset Details</h3>
<table class="kv">
  <tr><td>Date of Manufacture</td><td>${(()=>{const d=asset.dom;if(!d)return"—";if(/^\d{2}\/\d{4}$/.test(d))return d;try{const dt=new Date(d);if(isNaN(dt))return d;return String(dt.getMonth()+1).padStart(2,"0")+"/"+dt.getFullYear();}catch{return d;}})()}</td></tr>
  <tr><td>Current Operator</td><td>${asset.operator||"—"}</td></tr>
  <tr><td>Airframe TSN</td><td>${fmtHHMM(af.currentFH)}</td></tr>
  <tr><td>Airframe CSN</td><td>${(af.currentFC||0).toLocaleString()}</td></tr>
  <tr><td>Data Current As Of</td><td>${asset._lastPeriod||"—"}</td></tr>
</table>
<h3>Operating Weights</h3>
<table><thead><tr><th>Parameter</th><th>kg</th><th>lb</th></tr></thead><tbody>
${[["MTOW","mtow","mtow_lb"],["Max Taxi Weight","mtw","mtw_lb"],["MZFW","mzfw","mzfw_lb"],["MLW","mlw","mlw_lb"]].map(([l,k,klb])=>`<tr><td>${l}</td><td>${asset.weights?.[k]?.toLocaleString()||"—"}</td><td>${asset.weights?.[klb]?.toLocaleString()||"—"}</td></tr>`).join("")}
</tbody></table>
<h3>Check History</h3>
<table><thead><tr><th>Check</th><th>Last Date</th><th>Last TSN</th><th>Last CSN</th><th>Next Due</th></tr></thead><tbody>
${(asset.checks||[]).map(c=>`<tr><td>${c.name}</td><td>${fmtDate(c.lastDate)}</td><td>${c.lastFH?.toLocaleString()||"—"}</td><td>${c.lastFC?.toLocaleString()||"—"}</td><td style="font-weight:700">${fmtDate(c.nextDate)}</td></tr>`).join("")}
</tbody></table>
<h3>Specifications</h3>
<table class="kv"><tbody>
<tr><td>Configuration</td><td>${asset.specs?.config||"—"}</td></tr>
<tr><td>Passenger Seating</td><td>${asset.specs?.seating||"—"}</td></tr>
<tr><td>Passenger Seating Config</td><td>${asset.specs?.seatConfig||"—"}</td></tr>
<tr><td>Passenger Seating Manufacturer</td><td>${asset.specs?.seatMfr||"—"}</td></tr>
<tr><td>Passenger Seats P/N</td><td>${asset.specs?.seatPN||"—"}</td></tr>
<tr><td>Attendant Seats</td><td>${asset.specs?.attendantSeats||"—"}</td></tr>
<tr><td>Galleys</td><td>${asset.specs?.galleys||"—"}</td></tr>
<tr><td>Lavatories</td><td>${asset.specs?.lavs||"—"}</td></tr>
<tr><td>Cargo Type</td><td>${asset.specs?.cargoType||"—"}</td></tr>
<tr><td>Winglets</td><td>${asset.specs?.winglets||"—"}</td></tr>
<tr><td>ADS-B</td><td>${asset.specs?.adsb?"Installed":"Not Installed"}</td></tr>
<tr><td>CPDLC</td><td>${asset.specs?.cpdlc?"Installed":"Not Installed"}</td></tr>
<tr><td>TCAS 7.1</td><td>${asset.specs?.tcas?"Installed":"Not Installed"}</td></tr>
<tr><td>Cockpit Door Surveillance System</td><td>${asset.specs?.cdss?"Installed":"Not Installed"}</td></tr>
<tr><td>Reinforced Flight Deck Door</td><td>${asset.specs?.rfdd?"Installed":"Not Installed"}</td></tr>
<tr><td>QAR</td><td>${asset.specs?.qar?"Installed":"Not Installed"}</td></tr>
<tr><td>Enhanced Mode-S</td><td>${asset.specs?.modeS?"Installed":"Not Installed"}</td></tr>
<tr><td>Electronic Flight Bag</td><td>${asset.specs?.efb?"Installed":"Not Installed"}</td></tr>
${(asset.specs?.custom||[]).filter(f=>f.label&&f.value).map(f=>'<tr><td>'+f.label+'</td><td>'+f.value+'</td></tr>').join("")}
</tbody></table>
${PAGE_FOOTER}<div class="pb"></div>
${engSec(asset.engines?.[0],1)}
${PAGE_FOOTER}<div class="pb"></div>
${engSec(asset.engines?.[1],2)}
${PAGE_FOOTER}<div class="pb"></div>
<h3>Landing Gear</h3>
${lgSec(lg.nose,"Nose Landing Gear")}
${lgSec(lg.left,"LH Main Landing Gear")}
${lgSec(lg.right,"RH Main Landing Gear")}
${(()=>{
    const wb=asset.wheelsBrakes||{};
    const rows=[["Wheels",wb.mainWheels],["Wheels",wb.noseWheels],["Brake Unit",wb.brakes]].filter(([,item])=>item&&(item.pn||item.mfr));
    if(!rows.length)return"";
    return`<table style="margin-bottom:14px"><thead><tr><th colspan="4" style="background:#323F42;color:#FFFFFF;font-size:11px">Wheels &amp; Brakes</th></tr><tr><th>Component</th><th>Qty</th><th>P/N</th><th>Manufacturer</th></tr></thead><tbody>${rows.map(([label,item])=>`<tr><td>${label}</td><td>${item.qty||"—"}</td><td>${item.pn||"—"}</td><td>${item.mfr||"—"}</td></tr>`).join("")}</tbody></table>`;
  })()}
<h3>APU — ${apu.sn||"—"}</h3>
<table class="kv">
  <tr><td>Part Number</td><td>${apu.pn||"—"}</td><td style="color:#6b7280;font-weight:600;width:120px">Serial Number</td><td>${apu.sn||"—"}</td></tr>
  <tr><td>Manufacturer</td><td>${apu.mfr||"—"}</td><td style="color:#6b7280;font-weight:600;width:120px"></td><td></td></tr>
  <tr><td>TSN</td><td>${fmtHHMM(apu.currentFH)}</td><td style="color:#6b7280;font-weight:600">CSN</td><td>${(apu.currentFC||0).toLocaleString()}</td></tr>
</table>
<table><thead><tr><th>LLP Descriptor</th><th>P/N</th><th>S/N</th><th>FC Remaining</th></tr></thead><tbody>${llpRows(apu.llps,apu.currentFC)}</tbody></table>
<p style="font-weight:700;font-size:10px;margin:8px 0 4px">APU Shop Visit History</p>
<table><thead><tr><th>Details</th><th>Date / MRO</th><th>TSN</th><th>CSN</th></tr></thead><tbody>${svRows(apu.shopVisits,apu.currentFH,apu.currentFC)}</tbody></table>
${(()=>{
    const lopaPhoto=(asset.photos||[]).find(p=>p.label==="LOPA");
    if(!lopaPhoto)return"";
    return`${PAGE_FOOTER}<div class="pb"></div>
<h3>LOPA — Layout of Passenger Accommodation</h3>
<div style="text-align:center;margin-top:10px">
  <img src="${lopaPhoto.url}" style="width:100%;max-height:680px;object-fit:contain;background:#fff;border-radius:4px;display:block;margin:0 auto"/>
</div>`;
  })()}
${(()=>{
    const avionicsPhotos=(asset.photos||[]).filter(p=>p.label==="Avionics");
    if(!avionicsPhotos.length)return"";
    const imgs=avionicsPhotos.map(p=>`<img src="${p.url}" style="width:100%;max-height:680px;object-fit:contain;background:#fff;border-radius:4px;display:block;margin:0 auto 10px"/>`).join("");
    return`${PAGE_FOOTER}<div class="pb"></div>
<h3>Avionics</h3>
<div style="text-align:center;margin-top:10px">
  ${imgs}
</div>`;
  })()}
${(()=>{
    const galleryPhotos=(asset.photos||[]).filter(p=>p.label!=="LOPA"&&p.label!=="Airframe"&&p.label!=="Avionics");
    if(!galleryPhotos.length)return"";
    const photoHtml=galleryPhotos.map(p=>`
      <div style="break-inside:avoid">
        <img src="${p.url}" style="width:100%;height:160px;object-fit:contain;background:#fff;border-radius:4px;display:block"/>
        <div style="text-align:center;font-size:10px;color:#6b7280;margin-top:4px;font-weight:600;text-transform:uppercase;letter-spacing:0.06em">${p.label||""}</div>
      </div>`).join("");
    return`${PAGE_FOOTER}<div class="pb"></div>
<h3>Photo Gallery</h3>
<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:8px">${photoHtml}</div>`;
  })()}
${PAGE_FOOTER}
</body></html>`;
}
